+@tailwind base;
+@tailwind components;
+@tailwind utilities;
+
+@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&family=JetBrains+Mono:wght@500;700&display=swap');
+
+@layer base {
+  body {
+    @apply bg-page text-brand-dark antialiased font-sans;
+  }
+}
+
+@layer components {
+  .btn-primary {
+    @apply inline-flex items-center justify-center rounded-xl font-semibold text-sm px-5 py-3
+           bg-brand-gold text-brand-dark
+           hover:brightness-105 active:brightness-95
+           focus:outline-none focus:ring-2 focus:ring-brand-gold/40
+           transition-all duration-200
+           disabled:opacity-40 disabled:cursor-not-allowed;
+  }
+  .btn-secondary {
+    @apply inline-flex items-center justify-center rounded-xl font-medium text-sm px-5 py-3
+           border-2 border-brand-light/50 text-brand-soft
+           hover:border-brand-gold hover:text-brand-dark
+           focus:outline-none focus:ring-2 focus:ring-brand-gold/20
+           transition-all duration-200
+           disabled:opacity-40 disabled:cursor-not-allowed;
+  }
+  .btn-ghost {
+    @apply inline-flex items-center justify-center rounded-xl text-sm font-medium px-3 py-2
+           text-brand-soft hover:text-brand-dark hover:bg-brand-gold/10
+           transition-colors;
+  }
+  .input-field {
+    @apply block w-full rounded-xl border-2 border-brand-light/50 bg-white px-4 py-3 text-sm text-brand-dark
+           placeholder:text-brand-muted/70
+           focus:border-brand-gold focus:ring-2 focus:ring-brand-gold/20 focus:outline-none
+           transition-all;
+  }
+  .label-field {
+    @apply block text-xs font-semibold text-brand-soft mb-1.5 tracking-wide;
+  }
+  .card {
+    @apply bg-white rounded-2xl border border-brand-light/40 p-6 shadow-sm;
+  }
+  .stat-card {
+    @apply card p-5 flex flex-col gap-1.5;
+  }
+  .stat-value {
+    @apply text-2xl font-bold text-brand-dark font-mono tracking-tight;
+  }
+  .stat-label {
+    @apply text-xs text-brand-muted font-medium tracking-wide;
+  }
+  .badge {
+    @apply inline-flex items-center rounded-full font-semibold text-xs px-3 py-1;
+  }
+  .badge-draft {
+    @apply badge bg-brand-light/30 text-brand-soft;
+  }
+  .badge-submitted {
+    @apply badge bg-success/20 text-green-700;
+  }
+  .badge-reviewed {
+    @apply badge bg-brand-gold/25 text-brand-dark;
+  }
+  .nav-link {
+    @apply block px-4 py-2.5 rounded-xl text-sm font-medium tracking-wide transition-all
+           text-brand-soft hover:text-brand-dark hover:bg-brand-gold/10;
+  }
+  .nav-link-active {
+    @apply nav-link bg-brand-gold/20 text-brand-dark font-semibold;
+  }
+}

